mapper.sql:
from aiw_closed_loop_run r
where 1 = 1

    and r.task_code = #{criteria.taskCode}


    and r.run_status = #{criteria.runStatus}


    and r.automation_level = #{criteria.automationLevel}


    and r.market_scope = #{criteria.marketScope}


    and r.theme_code = #{criteria.themeCode}


    and r.mock_user_biz_id = #{criteria.mockUserBizId}


    and r.started_at >= #{criteria.startedFrom}


    and r.started_at <= #{criteria.startedTo}

mapper.select:
select r.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
